#!/usr/bin/env node
/**
 * check-character-rules.mjs - typography drift gate for prose files
 * (W-149).
 *
 * The 0.6.0 character-rules sweep replaced em/en dashes and curly
 * quotes with ASCII punctuation "across all markdown, TSDoc, and
 * user-facing strings", but had no gate: the drift class resurfaced in
 * exactly the files the sweep missed (examples/TRACING.md, NOTICE,
 * package READMEs). This script makes the sweep's claim enforceable
 * for the markdown layer plus the explicitly listed root text files.
 *
 * Scope: every tracked *.md except documentation/api/** (generated by
 * TypeDoc from TSDoc, which is source-level territory), fixture trees
 * (**\/__fixtures__/**, **\/tests/fixtures/**), plus EXTRA_FILES
 * (NOTICE). Code blocks inside markdown are NOT exempt: the sweep
 * covered them too and the current tree has no legitimate hits.
 *
 * Deliberately out of scope for this gate: TSDoc and string literals
 * in .ts sources - enforcing those needs a biome/eslint rule with
 * scope decisions of its own; extending coverage there is a separate
 * work item, so this gate does not claim it.
 *
 * Exit codes: 0 ok · 1 forbidden codepoints found · 2 invocation
 * error.
 */

import { execFileSync } from 'node:child_process';
import { readFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..');

/** Codepoints the character rules forbid, with human-readable names. */
export const FORBIDDEN = new Map([
  [0x2010, 'HYPHEN (U+2010)'],
  [0x2011, 'NON-BREAKING HYPHEN (U+2011)'],
  [0x2012, 'FIGURE DASH (U+2012)'],
  [0x2013, 'EN DASH (U+2013)'],
  [0x2014, 'EM DASH (U+2014)'],
  [0x2212, 'MINUS SIGN (U+2212)'],
  [0x2018, 'LEFT SINGLE QUOTATION MARK (U+2018)'],
  [0x2019, 'RIGHT SINGLE QUOTATION MARK (U+2019)'],
  [0x201c, 'LEFT DOUBLE QUOTATION MARK (U+201C)'],
  [0x201d, 'RIGHT DOUBLE QUOTATION MARK (U+201D)'],
]);

/**
 * Files exempt from the rules. Each entry must carry a reason (for
 * example verbatim upstream boilerplate or quoted external text). An
 * empty list is the healthy state.
 *
 * @type {ReadonlyArray<{ file: string; reason: string }>}
 */
export const ALLOWLIST = [];

/** Root-level non-markdown prose files that must also obey the rules. */
const EXTRA_FILES = ['NOTICE'];

const EXCLUDED = [/^documentation\/api\//, /(?:^|\/)__fixtures__\//, /(?:^|\/)tests\/fixtures\//];

/** True when the repo-relative path is outside this gate's scope. */
export function isExcluded(file) {
  return EXCLUDED.some((re) => re.test(file));
}

/** Tracked files in scope, repo-relative with forward slashes. */
export function collectFiles() {
  const tracked = execFileSync('git', ['ls-files', '-z', '*.md', ...EXTRA_FILES], {
    cwd: ROOT,
    encoding: 'utf8',
  })
    .split('\0')
    .filter(Boolean);
  return tracked.filter((f) => !isExcluded(f));
}

/**
 * Scan one file's text. Returns `{ line, column, name }` per hit so
 * the caller can print file:line:column plus the codepoint name.
 */
export function scanText(text) {
  const hits = [];
  const lines = text.split('\n');
  for (let i = 0; i < lines.length; i += 1) {
    const line = lines[i];
    for (let j = 0; j < line.length; j += 1) {
      const name = FORBIDDEN.get(line.codePointAt(j));
      if (name !== undefined) hits.push({ line: i + 1, column: j + 1, name });
    }
  }
  return hits;
}

export function run() {
  const allowed = new Set(ALLOWLIST.map((a) => a.file));
  let bad = 0;
  for (const file of collectFiles()) {
    if (allowed.has(file)) continue;
    let text;
    try {
      text = readFileSync(join(ROOT, file), 'utf8');
    } catch (err) {
      // `git ls-files` reads the INDEX: a tracked file deleted from
      // the working tree but not yet staged (e.g. changesets consumed
      // by a release version pass) still lists. Nothing on disk means
      // nothing to scan.
      if (err !== null && typeof err === 'object' && err.code === 'ENOENT') continue;
      throw err;
    }
    const hits = scanText(text);
    for (const h of hits) {
      console.error(`${file}:${h.line}:${h.column}: ${h.name}`);
      bad += 1;
    }
  }
  if (bad > 0) {
    console.error(
      `check-character-rules: FAIL - ${bad} forbidden codepoint(s). ` +
        'Replace with ASCII punctuation (hyphen, comma, colon, straight quotes) ' +
        'or add the file to ALLOWLIST with a justifying reason.',
    );
    return 1;
  }
  console.log('check-character-rules: OK');
  return 0;
}

export function selfTest() {
  // Forbidden codepoints are spelled as escapes so this file itself
  // stays free of them.
  const cases = [
    ['em dash detected', 'a \u2014 b', 1],
    ['en dash detected', '2020\u20132021', 1],
    ['curly apostrophe detected', 'it\u2019s', 1],
    ['curly double quotes detected', '\u201Cquoted\u201D', 2],
    ['minus sign detected', 'x \u2212 y', 1],
    ['ascii hyphen allowed', 'well-known - and ranges 1-2', 0],
    ['straight quotes allowed', `it's a "quote"`, 0],
    ['multiline positions', 'ok\nbad \u2014 here', 1],
  ];
  let failed = 0;
  for (const [label, text, expected] of cases) {
    const got = scanText(text).length;
    if (got !== expected) {
      console.error(`self-test FAIL: ${label} (expected ${expected}, got ${got})`);
      failed += 1;
    }
  }
  const multi = scanText('ok\nbad \u2014 here')[0];
  if (multi.line !== 2 || multi.column !== 5) {
    console.error(`self-test FAIL: position (got line ${multi.line} column ${multi.column})`);
    failed += 1;
  }
  const exclusion = [
    ['documentation/api/@graphorin/core/README.md', true],
    ['packages/tools/tests/fixtures/skill/SKILL.md', true],
    ['packages/x/tests/__fixtures__/doc.md', true],
    ['documentation/guide/memory-system.md', false],
    ['NOTICE', false],
  ];
  for (const [file, expected] of exclusion) {
    if (isExcluded(file) !== expected) {
      console.error(`self-test FAIL: exclusion of ${file} (expected ${expected})`);
      failed += 1;
    }
  }
  for (const entry of ALLOWLIST) {
    if (!entry.file || !entry.reason || entry.reason.length < 10) {
      console.error(`self-test FAIL: allowlist entry without a justifying reason: ${entry.file}`);
      failed += 1;
    }
  }
  if (failed > 0) return 1;
  console.log(
    `check-character-rules self-test: OK (${cases.length + 1 + exclusion.length} checks)`,
  );
  return 0;
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  try {
    process.exit(process.argv.includes('--self-test') ? selfTest() : run());
  } catch (err) {
    console.error('check-character-rules: ERROR');
    console.error(err);
    process.exit(2);
  }
}
